const hexPath = env.get('hex_path');
const target = env.get('openocd_target');
const iface = env.get('openocd_interface');

if (!hexPath) {
    node.error('hex_path env var must be set', msg);
    return null;
}

msg._start = Date.now();
msg._hex_path = hexPath;
msg._log_buffer = '';
msg.payload = `openocd -f ${iface} -f ${target} -c "program ${hexPath} verify reset exit" 2>&1`;
return msg;

// exec node routes stdout→out0, stderr→out1, exit-code→out2. All wired here.
const log = (typeof msg.payload === 'string') ? msg.payload : JSON.stringify(msg.payload);
const rc = msg.rc && typeof msg.rc.code === 'number' ? msg.rc.code : null;

if (rc === null) {
    // Buffer stdout/stderr; wait for exit-code msg.
    msg._log_buffer = (msg._log_buffer || '') + log;
    return null;
}

const fullLog = (msg._log_buffer || '') + log;
const elapsed = Date.now() - msg._start;
const success = rc === 0 && (fullLog.includes('Verified OK') || fullLog.includes('wrote'));

msg.payload = {
    success,
    hex_path: msg._hex_path,
    elapsed_ms: elapsed,
    exit_code: rc,
    timestamp: new Date().toISOString(),
    log: fullLog.split('\n').slice(-15).join('\n')
};

delete msg._start;
delete msg._hex_path;
delete msg._log_buffer;
return msg;
